{{ config(materialized=\'table\') }}\n\nSELECT\n    id AS \"Id\",\n    COALESCE(name, \'N/A\') AS \"Name\",\n    CASE UPPER(TRIM(stagename))\n        WHEN \'PROSPECTING\' THEN \'Prospecting\'\n        WHEN \'PROSPECT\' THEN \'Prospecting\'\n        WHEN \'IN KONTAKT\' THEN \'Prospecting\'\n        WHEN \'QUALIFICATION\' THEN \'Qualification\'\n        WHEN \'QUALIFIKATION\' THEN \'Qualification\'\n        WHEN \'QUALI\' THEN \'Qualification\'\n        WHEN \'IN PRĂśFUNG\' THEN \'Needs Analysis\'\n        WHEN \'CLOSED WON\' THEN \'Closed Won\'\n        WHEN \'WON\' THEN \'Closed Won\'\n        WHEN \'GEWONNEN\' THEN \'Closed Won\'\n        WHEN \'ABGESCHLOSSEN (GEWONNEN)\' THEN \'Closed Won\'\n        WHEN \'CLOSED LOST\' THEN \'Closed Lost\'\n        WHEN \'LOST\' THEN \'Closed Lost\'\n        WHEN \'VERLOREN\' THEN \'Closed Lost\'\n        WHEN \'ABGESCHLOSSEN (VERLOREN)\' THEN \'Closed Lost\'\n        ELSE \'Prospecting\' -- Default for NOT NULL target\n    END AS \"StageName\",\n    COALESCE(\n        CASE\n            WHEN closedate ~ \'^\\d{4}-\\d{2}-\\d{2}$\' THEN closedate::DATE\n            WHEN closedate ~ \'^\\d{2}\\.\\d{2}\\.\\d{4}$\' THEN TO_DATE(closedate, \'DD.MM.YYYY\')\n            WHEN closedate ~ \'^\\d{8}$\' THEN TO_DATE(closedate, \'YYYYMMDD\')\n            WHEN closedate ~ \'^\\d{1,2}/\\d{1,2}/\\d{4}$\' THEN TO_DATE(closedate, \'MM/DD/YYYY\')\n            ELSE NULL\n        END,\n        CURRENT_DATE\n    )::TEXT AS \"CloseDate\", -- Cast back to text for target spec\n    CASE\n        WHEN TRIM(amount) = \'\' OR TRIM(amount) IS NULL OR TRIM(amount) = \'None\' THEN NULL\n        ELSE\n            CAST(REGEXP_REPLACE(\n                REGEXP_REPLACE(\n                    REGEXP_REPLACE(\n                        REGEXP_REPLACE(LOWER(TRIM(amount)), \'^(eur|usd|gbp|chf|euro|dollar|ÂŁ|\\$|â‚¬)\s*|\s*(eur|usd|gbp|chf|euro|dollar|ÂŁ|\\$|â‚¬)$\', \'\', \'gi\'),\n                        \'\\.\', \'\', \'g\' -- Remove thousand separators (European format)\n                    ),\n                    \',\' , \'.\' -- Replace comma with dot for decimal (European format)\n                ),\n                \'[^\d\\.\\-]\', \'\', \'g\' -- Remove any remaining non-numeric, non-dot, non-dash characters\n            ) AS DOUBLE PRECISION)\n    END AS \"Amount\",\n    CASE UPPER(TRIM(currencyisocode))\n        WHEN \'EUR\' THEN \'EUR\'\n        WHEN \'EURO\' THEN \'EUR\'\n        WHEN \'â‚¬\' THEN \'EUR\'\n        WHEN \'USD\' THEN \'USD\'\n        WHEN \'DOLLAR\' THEN \'USD\'\n        WHEN \'$\' THEN \'USD\'\n        WHEN \'GBP\' THEN \'GBP\'\n        WHEN \'ÂŁ\' THEN \'GBP\'\n        WHEN \'CHF\' THEN \'CHF\'\n        ELSE UPPER(TRIM(currencyisocode)) -- Keep original if not standard\n    END AS \"CurrencyIsoCode\",\n    accountid AS \"AccountId\",\n    id AS \"Legacy_Opportunity_ID__c\",\n    NULL AS \"CreatedDate\",\n    NULL AS \"LastModifiedDate\",\n    0 AS \"IsDeleted\"\nFROM\n    {{ source(\'fixture_messy_data_v2_src\', source_table) }}\n